'use client'
import { useState } from 'react'
import Link from 'next/link'
import { motion } from 'framer-motion'
import { LayoutDashboard, ShoppingCart, Boxes, CreditCard, Menu } from 'lucide-react'
import { cn } from '@/lib/utils'

const nav = [
  { href: '/', label: 'Dashboard', icon: LayoutDashboard },
  { href: '/pos', label: 'POS', icon: ShoppingCart },
  { href: '/inventory', label: 'Inventory', icon: Boxes },
  { href: '/checkout', label: 'Checkout', icon: CreditCard }
]

export function Sidebar() {
  const [open, setOpen] = useState(true)
  return (
    <div className={cn('glass h-full p-3', open ? 'w-64' : 'w-20', 'rounded-2xl transition-all')}>
      <div className="flex items-center justify-between">
        <motion.button whileHover={{ rotate: 8, scale: 1.05 }} onClick={() => setOpen(!open)} className="p-2 rounded-xl card">
          <Menu className="size-5" />
        </motion.button>
        {open && <div className="font-semibold">POS</div>}
      </div>
      <div className="mt-6 space-y-2">
        {nav.map(({ href, label, icon: Icon }) => (
          <Link key={href} href={href} className="block">
            <motion.div whileHover={{ scale: 1.02 }} className="flex items-center gap-3 p-3 rounded-xl card">
              <motion.div whileHover={{ rotate: 6 }}>
                <Icon className="size-5" />
              </motion.div>
              {open && <span>{label}</span>}
            </motion.div>
          </Link>
        ))}
      </div>
    </div>
  )
}
