'use client'
import { useEffect, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Search } from 'lucide-react'
import { cn } from '@/lib/utils'
import Link from 'next/link'

const items = [
  { label: 'Go to Dashboard', href: '/' },
  { label: 'Open POS', href: '/pos' },
  { label: 'View Inventory', href: '/inventory' }
]

export function CommandPalette() {
  const [open, setOpen] = useState(false)
  const [q, setQ] = useState('')

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === 'k') {
        e.preventDefault()
        setOpen(true)
      }
      if (e.key === 'Escape') setOpen(false)
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [])

  const filtered = items.filter(i => i.label.toLowerCase().includes(q.toLowerCase()))

  return (
    <>
      <button onClick={() => setOpen(true)} className="flex items-center gap-2 px-3 py-2 rounded-xl card">
        <motion.div whileHover={{ rotate: 6 }}><Search className="size-4" /></motion.div>
        <span className="text-sm text-text-muted">Search CMD+K</span>
      </button>
      <AnimatePresence>
        {open && (
          <motion.div className="fixed inset-0 z-50 flex items-start justify-center pt-28 bg-black/40" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            <motion.div className={cn('w-full max-w-xl rounded-2xl p-4 glass')}>
              <input value={q} onChange={e => setQ(e.target.value)} placeholder="Search" className="w-full p-3 rounded-xl card outline-none" />
              <div className="mt-3 space-y-2">
                {filtered.map(i => (
                  <Link key={i.href} href={i.href} onClick={() => setOpen(false)} className="block">
                    <div className="p-3 rounded-xl card">{i.label}</div>
                  </Link>
                ))}
                {filtered.length === 0 && <div className="p-3 rounded-xl card">No results</div>}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}
